.Net solution with sliding window


    public static int LongestSubStringWithKChars(string source, int numberOfDistinctChars)
    {
        int len = 0;
        int rigthPointer =0;
        int leftPointer =0;
        int counter =0;

        Dictionary<char int> dictFrequency = new Dictionary<char int>();

        while(rightPointer < source.Length)
        {
            char rigthValue = source[rightPointer];

            if(dictFrequency.ContainsKey(rigthValue))
                dictFrequency[rigthValue] = dictFrequency[rigthValue] +1;
            else 
                dictFrequency.Add(rigthValue, 1);

            if(dictFrequency[rigthValue] == 1) counter++;

            rigthPointer++;

            while (counter > numberOfDistinctChars)
            {
                char leftValue = source[leftPointer];

                 if(dictFrequency.ContainsKey(leftValue))
                 {
                      dictFrequency[leftValue] = dictFrequency[leftValue] -1;

                      if(dictFrequency[leftValue] == 0) counter--;                  
                 }

                leftPointer++;

            }

            len = Math.Max(len, rightPointer- leftPointer);
        }

        return len;
    }

