class Solution {
    fun longestSubstring(s: String, m: Int): Int {
        var l = 0
        var r = 0
        val unique = HashMap<Char, Int>()
        while (r < s.length) {
            unique.putIfAbsent(s[r], 0)
            unique[s[r]] = unique[s[r]]!! + 1
            if (unique.size > m) {
                unique[s[l]] = unique[s[l]]!! - 1
                if (unique[s[l]] == 0) unique.remove(s[l])
                l++
            }
            r++
        }

        return r - l
    }
}
