**Simple C++ solution without maps or frequencies, just using set**
```c++
  static int lengthOfLongestSubstringKDistinct(const string& s, int k) {
    int maxLength = 0, windowStart = 0;
    unordered_set<char> found;

    for (int windowEnd = 0; windowEnd < s.size();) {
      found.insert(s[windowEnd]);

      if (found.size() > k) {
        windowStart++;
        windowEnd = windowStart;

        found.clear();
      } else {
        maxLength = max(windowEnd - windowStart + 1, maxLength);
        windowEnd++;
      }
    }

    return maxLength;
  }
